// tree diameter, bfs
class Solution {
public:
    string findSpecialNodes(int n, vector<vector<int>>& edges) {
        vector<vector<int>> adj(size(edges) + 1);
        for (const auto& e : edges) {
            adj[e[0]].emplace_back(e[1]);
            adj[e[1]].emplace_back(e[0]);
        }
        const auto& bfs = [&](int u) {
            vector<bool> lookup(size(adj));
            lookup[u] = true;
            vector<int> q = {u}, new_q;
            while (!empty(q)) {
                new_q.clear();
                for (const auto& u : q) {
                    for (const auto& v : adj[u]) {
                        if (lookup[v]) {
                            continue;
                        }
                        lookup[v] = true;
                        new_q.emplace_back(v);
                    }
                }
                swap(q, new_q);
            }
            return new_q;
        };

        string result(n, '0');
        const auto& far = bfs(0);
        for (const auto& u : far) {
            result[u] = '1';
        }
        for (const auto& u : bfs(far[0])) {
            result[u] = '1';
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(n)

# tree diameter, bfs
class Solution(object):
    def findSpecialNodes(self, n, edges):
        """
        :type n: int
        :type edges: List[List[int]]
        :rtype: str
        """
        def bfs(u):
            lookup = [False]*len(adj)
            lookup[u] = True
            q = [u]
            new_q = []
            while q:
                new_q = []
                for u in q:
                    for v in adj[u]:
                        if lookup[v]:
                            continue
                        lookup[v] = True
                        new_q.append(v)
                q, new_q = new_q, q
            return new_q

        adj = [[] for _ in xrange(len(edges)+1)]
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)
        result = ['0']*n
        far = bfs(0)
        for u in far:
            result[u] = '1'
        for u in bfs(far[0]):
            result[u] = '1'
        return "".join(result)
